def count_nums(arr):
    count = 0
    for num in arr:
        digit_sum = 0
        str_num = str(abs(num))
        for i, digit in enumerate(str_num):
            if num < 0 and i == 0:
                digit_sum -= int(digit)
            else:
                digit_sum += int(digit)
        if digit_sum > 0:
            count += 1
    return count
